sys_transform_script.script:
(function runTransformScript(source, map, log, target /*undefined onStart*/ ) {
    var EQIX_ACCCONT_UTIL = new EQIX_AccountContact_Util();

    // ---------- READ ASSOCIATED ACCOUNTS FROM SOURCE ----------
    var assocStr = (source && source.u_associatedaccounts_arraydata) ? String(source.u_associatedaccounts_arraydata) : '';
    if (!assocStr) {
        gs.warn('Post-Processing Contacts: source.u_associatedaccounts_arraydata is empty or undefined; nothing to process.');
        return;
    }

    try {
        assocArr = JSON.parse(assocStr);
        if (!Array.isArray(assocArr)) {
            gs.warn('Post-Processing Contacts: Parsed associated accounts but result is not an array. Value=' + assocStr);
            return;
        }
    } catch (e) {
        gs.error('Post-Processing Contacts: Failed to parse source.u_associatedaccounts_arraydata. Error=' + e.message + ' Value=' + assocStr);
        return;
    }

    //gs.info('Post-Processing Contacts: Processing ' + assocArr.length + ' associated account(s) for contact=' + contactSysId);


    // ---------- MAIN LOOP ----------
    for (var idx = 0; idx < assocArr.length; idx++) {
        var accountObj = assocArr[idx] || {};
        var accountMdmId = accountObj.accountMdmId ? String(accountObj.accountMdmId) : '';
        var contactMdmId = source.u_mdmid;
        var accountName = accountObj.accountName ? String(accountObj.accountName) : '';


        if (!accountMdmId && !accountName) {
            gs.warn('Post-Processing Contacts: Row ' + idx + ' has neither accountMdmId nor accountName; skipping.');
            continue;
        }

        var accountSysIds = EQIX_ACCCONT_UTIL.resolveAccountSysId(accountMdmId);
        if (!accountSysIds || accountSysIds.length == 0) {
            gs.warn('Post-Processing Contacts: Row ' + idx + ' account not found (MDM=' + accountMdmId + '); skipping.');
            continue;
        }

        var contactSysId = EQIX_ACCCONT_UTIL.resolveContactSysId(contactMdmId);
        if (!contactSysId) {
            gs.warn('Post-Processing Contacts: Row ' + idx + ' account not found (MDM=' + contactSysId + '); skipping.');
            continue;
        }


        if (EQIX_ACCCONT_UTIL.permissionExists(accountSysIds, contactSysId)) {
            gs.info('Post-Processing Contacts: Row ' + idx + ' permission already exists for account=' + accountSysIds + ' contact=' + contactSysId + '; skipping.');
            continue;
        }

        var newPermIds = EQIX_ACCCONT_UTIL.insertCustomerPermission(accountSysIds, contactSysId);
        if (newPermIds) {
            gs.info('Post-Processing Contacts: Row ' + idx + ' permission inserted: ' + newPermIds.join(',') +
                ' [account=' + accountSysIds.join(',') + ', contact=' + contactSysId + ']');
        } else {
            gs.error('Post-Processing Contacts: Row ' + idx + ' failed to insert permission ' +
                '[account=' + accountSysIds.join(',') + ', contact=' + contactSysId + ']');
        }
    }


})(source, map, log, target);
